  } finally {
    _psdPending = false;
    if (Math.abs(S.viewStart - t0) > 0.05 || Math.abs(S.viewStart + S.viewDur - t1) > 0.05)
      _psdTimer = setTimeout(fetchPSD, 80);
  }
}
