function _freqPanBlended(fH0, fL0, frac) {
  const a = S.logScale;
  if (a < 0.001 || fL0 <= 0) {
    const df = frac * (fH0 - fL0);
    return { fH: fH0 + df, fL: fL0 + df };
  }
  const r = Math.pow(fH0 / fL0, frac);
  if (a > 0.999) return { fH: fH0 * r, fL: fL0 * r };
  const df = frac * (fH0 - fL0);
  return {
    fH: (1 - a) * (fH0 + df) + a * (fH0 * r),
    fL: (1 - a) * (fL0 + df) + a * (fL0 * r),
  };
}
```
